#include "concurrent_operations.h"

__global__ void kernelSquare(int *data, int size)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < size)
    {
        data[i] = data[i] * data[i];
    }
}

__global__ void kernelIncrement(int *data, int size)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < size)
    {
        data[i] += 1;
    }
}

__global__ void kernelDouble(int *data, int size)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < size)
    {
        data[i] *= 2;
    }
}

__global__ void kernelAdd(int *result, const int *a, const int *b, int size)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < size)
    {
        result[i] = a[i] + b[i];
    }
}

void calculateOnCPU(int *result, const int *arrayX, const int *arrayY, const int *arrayZ, int size)
{
    for (int i = 0; i < size; ++i)
    {
        int X_prime = arrayX[i] * arrayX[i];
        int Y_prime = arrayY[i] + 1;
        int Z_prime = arrayZ[i] * 2;
        int A       = X_prime + Y_prime;
        int B       = arrayY[i] + Z_prime;
        result[i]   = (A + B) * (A + B);
    }
}

#ifndef CONCURRENT_OPERATIONS_H
#define CONCURRENT_OPERATIONS_H

// Kernel function declarations
__global__ void kernelSquare(int *data, int size);
__global__ void kernelIncrement(int *data, int size);
__global__ void kernelDouble(int *data, int size);
__global__ void kernelAdd(int *result, const int *a, const int *b, int size);

// Main function to implement
void performComplexConcurrentOperations(int *result, const int *arrayX, const int *arrayY,
                                        const int *arrayZ, int size);

// CPU validation function
void calculateOnCPU(int *result, const int *arrayX, const int *arrayY, const int *arrayZ, int size);

#endif // CONCURRENT_OPERATIONS_H

