#include "concurrent_operations.h"
#include <cassert>
#include <cstdlib>

int launch()
{
    const int size = 1 << 20;   // 1M elements
    int *arrayX    = new int[size];
    int *arrayY    = new int[size];
    int *arrayZ    = new int[size];
    int *result    = new int[size];
    int *expected  = new int[size];

    // Generate random test data
    for (int i = 0; i < size; ++i)
    {
        arrayX[i] = rand() % 100;
        arrayY[i] = rand() % 10;
        arrayZ[i] = rand() % 50;
    }
    // Perform the operations on the GPU
    performComplexConcurrentOperations(result, arrayX, arrayY, arrayZ, size);

    // Calculate the expected results on the CPU
    calculateOnCPU(expected, arrayX, arrayY, arrayZ, size);

    // Verify the results
    for (int i = 0; i < size; ++i)
    {
        assert(result[i] == expected[i]);
    }

    // Clean up
    delete[] arrayX;
    delete[] arrayY;
    delete[] arrayZ;
    delete[] result;
    delete[] expected;

    return 0;
}

int main() {
    launch();
}
